using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

Console.WriteLine("Research Agent Starting...");

var topic = args.Length > 0 ? string.Join(" ", args) : "the impact of quantum computing on cryptography";
Console.WriteLine($"Researching topic: {topic}\n");

// Configure the chat client with tools
var openAiClient = new OpenAIClient(Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "your-api-key");
IChatClient chatClient = openAiClient
    .GetChatClient("gpt-4o-mini")
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// Create tools
var searchTool = AIFunctionFactory.Create(WebSearchTool.Search);
var noteTool = AIFunctionFactory.Create(NoteTakingTool.SaveNote);
var getNotesTool = AIFunctionFactory.Create(NoteTakingTool.GetNotes);

var chatOptions = new ChatOptions
{
    Tools = [searchTool, noteTool, getNotesTool],
    Temperature = 0.7f
};

var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your job is to research a given topic thoroughly.
        Use the web_search tool to find information, and the save_note tool to record
        key findings as you go. Search multiple aspects of the topic to build a
        comprehensive understanding. After researching, use get_notes to review what
        you've collected, then provide a final summary.
        """),
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}")
};

Console.WriteLine("Agent is researching...\n");

var response = await chatClient.GetResponseAsync(messages, chatOptions);

Console.WriteLine("=== Research Summary ===\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n=== Collected Notes ===\n");
foreach (var note in NoteTakingTool.Notes)
{
    Console.WriteLine($"• {note}");
}

// --- Tool Definitions ---

public static class WebSearchTool
{
    [Description("Searches the web for information on a given query and returns results.")]
    public static string Search([Description("The search query")] string query)
    {
        // Simulated web search results for demonstration
        Console.WriteLine($"  [Tool] Searching web for: \"{query}\"");

        var results = query.ToLowerInvariant() switch
        {
            var q when q.Contains("quantum") && q.Contains("cryptography") =>
                "Quantum computers threaten current RSA and ECC encryption by running Shor's algorithm. " +
                "NIST finalized post-quantum cryptography standards in 2024 including ML-KEM (Kyber) and ML-DSA (Dilithium). " +
                "Experts estimate cryptographically relevant quantum computers could arrive by 2030-2035.",

            var q when q.Contains("post-quantum") || q.Contains("pqc") =>
                "Post-quantum cryptography (PQC) uses lattice-based, hash-based, and code-based approaches. " +
                "NIST standardized FIPS 203 (ML-KEM), FIPS 204 (ML-DSA), and FIPS 205 (SLH-DSA) in August 2024. " +
                "Major tech companies are already migrating: Google uses Kyber in Chrome, Apple adopted PQ3 in iMessage.",

            var q when q.Contains("shor") || q.Contains("algorithm") =>
                "Shor's algorithm can factor large integers and compute discrete logarithms in polynomial time on a quantum computer. " +
                "This breaks RSA, DSA, and ECDSA. Current quantum computers have ~1000 qubits but breaking RSA-2048 requires ~4000 logical qubits.",

            var q when q.Contains("harvest") || q.Contains("store now") =>
                "\"Harvest now, decrypt later\" (HNDL) attacks involve adversaries collecting encrypted data today to decrypt once quantum computers are available. " +
                "Government agencies and enterprises are prioritizing early migration to PQC to counter this threat.",

            var q when q.Contains("timeline") || q.Contains("when") =>
                "IBM targets 100,000 qubits by 2033. Google aims for a useful error-corrected quantum computer by 2029. " +
                "The NSA requires national security systems to transition to PQC by 2035.",

            _ =>
                $"Search results for '{query}': Various sources discuss this topic with multiple perspectives " +
                "and ongoing research developments. Key findings suggest significant progress in recent years."
        };

        return results;
    }
}

public static class NoteTakingTool
{
    public static List<string> Notes { get; } = [];

    [Description("Saves a research note for later reference. Use this to record key findings during research.")]
    public static string SaveNote([Description("The note content to save")] string note)
    {
        Notes.Add(note);
        Console.WriteLine($"  [Tool] Note saved ({Notes.Count} total)");
        return $"Note saved successfully. Total notes: {Notes.Count}";
    }

    [Description("Retrieves all saved research notes.")]
    public static string GetNotes()
    {
        if (Notes.Count == 0)
            return "No notes saved yet.";

        Console.WriteLine($"  [Tool] Retrieving {Notes.Count} notes");
        return string.Join("\n", Notes.Select((n, i) => $"{i + 1}. {n}"));
    }
}

